/**
 * seed-global-country-intel.mjs
 * Seeds country intel for all world countries organized by region.
 * - Updates existing MENA countries to use region="MENA"
 * - Inserts all other world countries with standardized data points
 * Run: node scripts/seed-global-country-intel.mjs
 */
import mysql2 from 'mysql2/promise';
import dotenv from 'dotenv';
dotenv.config();

const conn = await mysql2.createConnection(process.env.DATABASE_URL);

// First, fix existing MENA countries to use region="MENA"
await conn.execute(`UPDATE country_intel_data SET region='MENA' WHERE region IN ('Gulf','Levant','North Africa','Middle East','Arabian Peninsula','Middle East / Europe')`);
console.log('✓ Updated existing MENA countries to region=MENA');

const upsert = async (row) => {
  const {
    country, isoA3, region, capital, governmentType, headOfState,
    population, gdpUsd, gdpPerCapita, militaryBudgetUsd, armedForcesSize,
    threatLevel, nuclearStatus, sanctionsStatus, unMemberStatus,
    keyLeaders, alliances, activeConflicts, humanRightsIndex,
    pressFreedomIndex, corruptionIndex, internetFreedom, keyIntelNotes, sources
  } = row;
  try {
    await conn.execute(
      `INSERT INTO country_intel_data
        (country, isoA3, region, capital, governmentType, headOfState,
         population, gdpUsd, gdpPerCapita, militaryBudgetUsd, armedForcesSize,
         threatLevel, nuclearStatus, sanctionsStatus, unMemberStatus,
         keyLeaders, alliances, activeConflicts, humanRightsIndex,
         pressFreedomIndex, corruptionIndex, internetFreedom, keyIntelNotes, sources, lastUpdated)
       VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,NOW())
       ON DUPLICATE KEY UPDATE
         isoA3=VALUES(isoA3), region=VALUES(region), capital=VALUES(capital),
         governmentType=VALUES(governmentType), headOfState=VALUES(headOfState),
         population=VALUES(population), gdpUsd=VALUES(gdpUsd), gdpPerCapita=VALUES(gdpPerCapita),
         militaryBudgetUsd=VALUES(militaryBudgetUsd), armedForcesSize=VALUES(armedForcesSize),
         threatLevel=VALUES(threatLevel), nuclearStatus=VALUES(nuclearStatus),
         sanctionsStatus=VALUES(sanctionsStatus), unMemberStatus=VALUES(unMemberStatus),
         keyLeaders=VALUES(keyLeaders), alliances=VALUES(alliances),
         activeConflicts=VALUES(activeConflicts), humanRightsIndex=VALUES(humanRightsIndex),
         pressFreedomIndex=VALUES(pressFreedomIndex), corruptionIndex=VALUES(corruptionIndex),
         internetFreedom=VALUES(internetFreedom), keyIntelNotes=VALUES(keyIntelNotes),
         sources=VALUES(sources), lastUpdated=NOW()`,
      [
        country, isoA3, region, capital, governmentType, headOfState,
        population, gdpUsd, gdpPerCapita, militaryBudgetUsd, armedForcesSize,
        threatLevel, nuclearStatus, sanctionsStatus || null, unMemberStatus || 'Member',
        JSON.stringify(keyLeaders || []),
        JSON.stringify(alliances || []),
        JSON.stringify(activeConflicts || []),
        humanRightsIndex || null, pressFreedomIndex || null, corruptionIndex || null,
        internetFreedom || null, keyIntelNotes || null,
        JSON.stringify(sources || [])
      ]
    );
  } catch(e) {
    console.error(`  ✗ ${country}: ${e.message}`);
  }
};

