// ─── RUN ALL BATCHES ──────────────────────────────────────────────────────────
const allBatches = [
  { label: 'Europe', data: europeCountries },
  { label: 'East Asia', data: eastAsiaCountries },
  { label: 'Asia-Pacific', data: asiaPacificCountries },
  { label: 'South Asia', data: southAsiaCountries },
  { label: 'Central Asia', data: centralAsiaCountries },
  { label: 'Sub-Saharan Africa', data: subSaharanCountries },
  { label: 'North Africa', data: northAfricaCountries },
  { label: 'Americas', data: americasCountries },
  { label: 'Latin America', data: latinAmericaCountries },
  { label: 'Global/MENA additions', data: globalCountries },
];

let totalUpserted = 0;
for (const batch of allBatches) {
  let count = 0;
  for (const row of batch.data) {
    await upsert(row);
    count++;
    totalUpserted++;
  }
  console.log(`  ✓ ${batch.label}: ${count} countries`);
}

console.log(`\nDone! Total upserted: ${totalUpserted} countries`);

const [rows] = await conn.execute('SELECT region, COUNT(*) as cnt FROM country_intel_data GROUP BY region ORDER BY cnt DESC');
console.log('\nFinal country intel counts per region:');
for (const row of rows) {
  console.log(`  ${row.region}: ${row.cnt}`);
}

const [total] = await conn.execute('SELECT COUNT(*) as cnt FROM country_intel_data');
console.log(`\nTotal countries in DB: ${total[0].cnt}`);

await conn.end();
